using System;using System.Collections.Generic;using System.Linq;class A{static int W,H;static int[,]T,LK;static Dictionary<string,string>[]RM=new Dictionary<string,string>[14];static Dictionary<string,string>OPP=new(){{"TOP","BOTTOM"},{"BOTTOM","TOP"},{"LEFT","RIGHT"},{"RIGHT","LEFT"}};static Dictionary<string,string>CW=new(){{"TOP","RIGHT"},{"RIGHT","BOTTOM"},{"BOTTOM","LEFT"},{"LEFT","TOP"}};static int[]DX={0,0,-1,1},DY={-1,1,0,0};static int Di(string s)=>s=="TOP"?0:s=="BOTTOM"?1:s=="LEFT"?2:3;static Dictionary<string,string>RotR(Dictionary<string,string>rm){var r=new Dictionary<string,string>();foreach(var(e,x)in rm)r[CW[e]]=CW[x];return r;}static Dictionary<int,Dictionary<string,string>>rots=new();static Dictionary<string,string>Gt(int x,int y)=>rots.ContainsKey(y*99+x)?rots[y*99+x]:RM[T[y,x]];static List<(int x,int y,Dictionary<string,string>t)>plan=new();static bool Dfs(int x,int y,string e){if(y>=H)return true;if(x<0||x>=W||y<0)return false;var o=RM[T[y,x]];var cs=new List<Dictionary<string,string>>();if(LK[y,x]==1)cs.Add(Gt(x,y));else{var t=new Dictionary<string,string>(o);for(int i=0;i<4;i++){cs.Add(new Dictionary<string,string>(t));t=RotR(t);}}int k=y*99+x;foreach(var c in cs){if(!c.ContainsKey(e))continue;var ex=c[e];int nx=x+DX[Di(ex)],ny=y+DY[Di(ex)];var ne=OPP[ex];Dictionary<string,string>prev=null;if(rots.ContainsKey(k))prev=rots[k];rots[k]=c;if(Dfs(nx,ny,ne)){if(!c.SequenceEqual(RM[T[y,x]]))plan.Add((x,y,c));return true;}if(prev!=null)rots[k]=prev;else rots.Remove(k);}return false;}static bool Eq(Dictionary<string,string>a,Dictionary<string,string>b)=>a.Count==b.Count&&a.All(kv=>b.ContainsKey(kv.Key)&&b[kv.Key]==kv.Value);static void Main(){var p=Console.ReadLine().Split(' ');W=int.Parse(p[0]);H=int.Parse(p[1]);RM[0]=new();RM[1]=new(){{"TOP","BOTTOM"},{"LEFT","BOTTOM"},{"RIGHT","BOTTOM"}};RM[2]=new(){{"TOP","RIGHT"},{"RIGHT","BOTTOM"}};RM[3]=new(){{"TOP","LEFT"},{"LEFT","BOTTOM"}};RM[4]=new(){{"TOP","LEFT"},{"LEFT","BOTTOM"}};RM[5]=new(){{"TOP","RIGHT"},{"RIGHT","BOTTOM"}};RM[6]=new(){{"TOP","RIGHT"},{"LEFT","BOTTOM"}};RM[7]=new(){{"TOP","LEFT"},{"RIGHT","BOTTOM"}};RM[8]=new(){{"LEFT","BOTTOM"},{"RIGHT","TOP"}};RM[9]=new(){{"RIGHT","BOTTOM"},{"LEFT","TOP"}};RM[10]=new(){{"LEFT","RIGHT"},{"RIGHT","LEFT"}};RM[11]=new(){{"TOP","BOTTOM"},{"BOTTOM","TOP"}};RM[12]=new(){{"TOP","RIGHT"},{"RIGHT","TOP"},{"LEFT","BOTTOM"},{"BOTTOM","LEFT"}};RM[13]=new(){{"TOP","LEFT"},{"LEFT","TOP"},{"RIGHT","BOTTOM"},{"BOTTOM","RIGHT"}};T=new int[H,W];LK=new int[H,W];for(int y=0;y<H;y++){p=Console.ReadLine().Split(' ');for(int x=0;x<W;x++){int v=int.Parse(p[x]);LK[y,x]=v<0?1:0;T[y,x]=Math.Abs(v);}}Console.ReadLine();var Q=new List<string>();for(;;){p=Console.ReadLine().Split(' ');int yi=int.Parse(p[0]),xi=int.Parse(p[1]);string en=p[2];int R=int.Parse(Console.ReadLine());for(int i=0;i<R;i++)Console.ReadLine();if(Q.Count==0){rots.Clear();plan.Clear();if(Dfs(xi,yi,en))foreach(var(sx,sy,tgt)in plan){var o=RM[T[sy,sx]];int r=0;var t=new Dictionary<string,string>(o);for(int i=0;i<4;i++){if(Eq(t,tgt)){r=i;break;}t=RotR(t);}if(r==0)continue;string d=r<=2?"RIGHT":"LEFT";int cnt=r<=2?r:4-r;for(int i=0;i<cnt;i++)Q.Add($"{sx} {sy} {d}");}}Console.WriteLine(Q.Count>0?Q[0]:"WAIT");if(Q.Count>0)Q.RemoveAt(0);Console.Out.Flush();}}}